import play.api.mvc.{AbstractController, ControllerComponents, Action}
import javax.inject.Inject
import scala.concurrent.ExecutionContext
import models.Order
import repositories.OrderRepository
import play.api.libs.json.Json

class OrderController @Inject()(cc: ControllerComponents, orderRepository: OrderRepository)(implicit ec: ExecutionContext) extends AbstractController(cc) {

  def getOrderById(orderId: Long) = Action.async { implicit request =>
    // Assuming we have a method to get the current user's tenant and role
    val currentUser = request.attrs.get(UserKey).get
    val tenantId = currentUser.tenantId
    val userRole = currentUser.role

    orderRepository.findById(orderId).flatMap {
      case Some(order) if order.tenantId == tenantId =>
        // Check if user has permission to view the order based on their role
        if (userRole == "admin" || order.userId == currentUser.id) {
          Future.successful(Ok(Json.toJson(order)))
        } else {
          Future.successful(Forbidden("You do not have permission to access this order"))
        }
      case Some(_) => Future.successful(Forbidden("Order does not belong to your tenant"))
      case None => Future.successful(NotFound("Order not found"))
    }
  }
}